import React from 'react';
import './CommandeList.css'; // optionnel
import { useEffect, useState } from 'react';
import axios from 'axios';

const CommandeList = ({ commandes = [], onSelect }) => {
  if (!Array.isArray(commandes)) {
    return <p>Aucune commande à afficher.</p>;
  }
  console.log(commandes);
  function CommandeList({ onSelect }) {
    const [commandes, setCommandes] = useState([]);
  
    useEffect(() => {
      axios.get('http://localhost:3001/commandes')
        .then((res) => {
          console.log("Données reçues :", res.data); // <== ICI
          setCommandes(res.data);
        })
        .catch((err) => console.error("Erreur lors du chargement des commandes:", err));
    }, []);
    
  
    return (
      <div>
        <h2>Liste des Commandes</h2>
        <table className="commande-table">
          <thead>
            <tr>
              <th>ID</th>
              <th>Client</th>
              <th>Article</th>
              <th>Quantité</th>
              <th>Date</th>
              <th>Actions</th>
            </tr>
          </thead>
          <tbody>
            {Array.isArray(commandes) && commandes.length > 0 ? (
              commandes.map((commande) => (
                <tr key={commande.idCOM}>
                  <td>{commande.idCOM}</td>
                  <td>{commande.nomCli}</td>
                  <td>{commande.libelle}</td>
                  <td>{commande.qte}</td>
                  <td>{commande.dateCom}</td>
                  <td>
                    <button onClick={() => onSelect(commande)}>
                      Modifier / Supprimer
                    </button>
                  </td>
                </tr>
              ))
            ) : (
              <tr>
                <td colSpan="6">Aucune commande trouvée.</td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    );
  }}
  
  export default CommandeList;
